const registerSchema = z
  .object({
    fullName: z
      .string()
      .min(2, "M├¡nimo 2 caracteres")
      .max(100, "M├íximo 100 caracteres"),
    username: z
      .string()
      .min(3, "M├¡nimo 3 caracteres")
      .max(30, "M├íximo 30 caracteres")
      .regex(
        /^[a-z0-9]([a-z0-9-]*[a-z0-9])?$/,
        "Solo letras min├║sculas, n├║meros y guiones"
      ),
    email: z.string().email("Ingresa un email v├ílido"),
    password: z.string().min(6, "M├¡nimo 6 caracteres"),
    confirmPassword: z.string().min(6, "Confirma tu contrase├▒a"),
  })
  .refine((data) => data.password === data.confirmPassword, {
    message: "Las contrase├▒as no coinciden",
    path: ["confirmPassword"],
  })

type RegisterFormData = z.infer<typeof registerSchema>

// Slugs reservados
const RESERVED_SLUGS = [
  "dashboard",
  "login",
  "register",
  "auth",
  "api",
  "blog",
  "admin",
  "settings",
  "reset-password",
  "terms",
  "privacy",
  "pricing",
  "wootienda",
  "www",
  "app",
  "help",
  "support",
]

export function RegisterForm() {
  const router = useRouter()
  const [isLoading, setIsLoading] = useState(false)
  const [slugStatus, setSlugStatus] = useState<
    "idle" | "checking" | "available" | "taken" | "reserved" | "invalid"
  >("idle")
  const [emailSent, setEmailSent] = useState(false)
  const supabase = createClient()

  const {
    register,
    handleSubmit,
    watch,
    formState: { errors },
  } = useForm<RegisterFormData>({
    resolver: zodResolver(registerSchema),
    mode: "onChange",
  })

  const username = watch("username")

  // Formatear username ÔåÆ slug en tiempo real
  const formatSlug = (value: string) =>
    value
      .toLowerCase()
      .replace(/\s+/g, "-")
      .replace(/[^a-z0-9-]/g, "")

  // Check slug availability (debounced)
  const checkSlug = useCallback(
    async (slug: string) => {
      if (!slug || slug.length < 3) {
        setSlugStatus("idle")
        return
      }

      const formatted = formatSlug(slug)

      if (RESERVED_SLUGS.includes(formatted)) {
        setSlugStatus("reserved")
        return
      }

      if (!/^[a-z0-9]([a-z0-9-]*[a-z0-9])?$/.test(formatted)) {
        setSlugStatus("invalid")
        return
      }

      setSlugStatus("checking")

      try {
        const { data, error } = await supabase
          .from("businesses")
          .select("slug")
          .eq("slug", formatted)
          .maybeSingle()

        if (error) {
          // Table might not exist yet ÔÇö treat as available
          setSlugStatus("available")
          return
        }

        setSlugStatus(data ? "taken" : "available")
      } catch {
        setSlugStatus("available")
      }
    },
    [supabase]
  )

  useEffect(() => {
    const timeout = setTimeout(() => {
      if (username) checkSlug(username)
    }, 500)
    return () => clearTimeout(timeout)
  }, [username, checkSlug])

  async function onSubmit(data: RegisterFormData) {
    setIsLoading(true)
    try {
      const { error } = await supabase.auth.signUp({
        email: data.email,
        password: data.password,
        options: {
          data: {
            full_name: data.fullName,
            username: formatSlug(data.username),
          },
          emailRedirectTo: `${window.location.origin}/auth/callback`,
        },
      })

      if (error) {
        toast.error("Error al crear cuenta", {
          description: error.message,
        })
        return
      }

      setEmailSent(true)
      toast.success("┬íCuenta creada!", {
        description: "Revisa tu email para confirmar tu cuenta.",
      })
    } catch {
      toast.error("Error inesperado. Intenta de nuevo.")
    } finally {
      setIsLoading(false)
    }
  }

  // Confirmation screen
  if (emailSent) {
    return (
      <div className="w-full max-w-md mx-auto text-center py-12">
        <div className="w-16 h-16 rounded-full bg-primary/10 text-primary flex items-center justify-center mx-auto mb-6">
          <Mail className="size-7" />
        </div>
        <h2 className="text-2xl font-bold tracking-tight mb-3">
          Revisa tu email
        </h2>
        <p className="text-muted-foreground mb-2">
          Hemos enviado un enlace de confirmaci├│n a tu correo electr├│nico.
        </p>
        <p className="text-sm text-muted-foreground mb-8">
          Tu URL ser├í:{" "}
          <span className="font-semibold text-foreground">
            wootienda.com/{formatSlug(username || "")}
          </span>
        </p>
        <Button variant="outline" asChild>
          <Link href="/login">
            <ArrowLeft className="size-4" />
            Ir a iniciar sesi├│n
          </Link>
        </Button>
      </div>
    )
  }

  return (
    <div className="w-full max-w-md mx-auto">
      {/* Back */}
      <Link
        href="/"
        className="inline-flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors mb-8"
      >
        <ArrowLeft className="size-4" />
        Volver al inicio
      </Link>

      {/* Header */}
      <div className="mb-8">
        <div className="mb-6">
          <Logo variant="both" size="sm" />
        </div>
        <h1 className="text-3xl font-bold tracking-tight mb-2">
          Crea tu cuenta
        </h1>
        <p className="text-muted-foreground">
          Registra tu negocio y obt├®n tu landing en minutos
        </p>
      </div>

      {/* Form */}
      <form onSubmit={handleSubmit(onSubmit)} className="space-y-5">
        {/* Full Name */}
        <div className="space-y-2">
